    TargetOutputSetPubSubType::TargetOutputSetPubSubType()
    {
        set_name("TargetFull::TargetOutputSet");
        uint32_t type_size = TargetFull_TargetOutputSet_max_cdr_typesize;
        type_size += static_cast<uint32_t>(eprosima::fastcdr::Cdr::alignment(type_size, 4)); /* possible submessage alignment */
        max_serialized_type_size = type_size + 4; /*encapsulation*/
        is_compute_key_provided = false;
        uint32_t key_length = TargetFull_TargetOutputSet_max_key_cdr_typesize > 16 ? TargetFull_TargetOutputSet_max_key_cdr_typesize : 16;
        key_buffer_ = reinterpret_cast<unsigned char*>(malloc(key_length));
        memset(key_buffer_, 0, key_length);
    }

